      const trunkRadius = Math.max(log.height * 0.44, 0.35);
      const trunk = new THREE.Mesh(new THREE.CylinderGeometry(1, 1, 1, 14), fallenLogBarkMat);
      trunk.rotation.z = Math.PI / 2;
