      const bandV = new THREE.Mesh(sharedGeometries.unitBox, stoneBlockBandMat);
      bandV.scale.set(0.2, crate.height + 0.08, crate.depth + 0.08);
      box.castShadow = true; box.receiveShadow = true;
      group.add(box, bandH, bandV);
